# --- Cache Helper Classes and Functions ---

class CacheManager:
    """Manages caching operations with Memcached."""

    def __init__(self, client):
        self.client = client

    def get(self, key):
        """Get a value from cache."""
        try:
            return self.client.get(key)
        except Exception as e:
            app.logger.error(f"Cache GET error for key '{key}': {e}")
            return None

    def set(self, key, value, ttl=None):
        """Set a value in cache with optional TTL."""
        if ttl is None:
            ttl = app.config['DEFAULT_CACHE_TTL']
        try:
            self.client.set(key, value, expire=ttl)
            return True
        except Exception as e:
            app.logger.error(f"Cache SET error for key '{key}': {e}")
            return False

    def delete(self, key):
        """Delete a value from cache."""
        try:
            self.client.delete(key)
            return True
        except Exception as e:
            app.logger.error(f"Cache DELETE error for key '{key}': {e}")
            return False

    def invalidate_pattern(self, prefix):
        """Invalidate cache entries by tracking keys with a prefix."""
        try:
            tracked_key = f"_tracked_keys:{prefix}"
            tracked = self.client.get(tracked_key)
            if tracked and isinstance(tracked, list):
                for key in tracked:
                    self.client.delete(key)
                self.client.delete(tracked_key)
            return True
        except Exception as e:
            app.logger.error(f"Cache INVALIDATE error for prefix '{prefix}': {e}")
            return False

    def track_key(self, prefix, key):
        """Track a cache key under a prefix for bulk invalidation."""
        try:
            tracked_key = f"_tracked_keys:{prefix}"
            tracked = self.client.get(tracked_key) or []
            if key not in tracked:
                tracked.append(key)
                self.client.set(tracked_key, tracked, expire=86400)  # 24h tracking
            return True
        except Exception as e:
            app.logger.error(f"Cache TRACK error: {e}")
            return False

    def get_stats(self):
        """Get Memcached server statistics."""
        try:
            stats = self.client.stats()
            decoded_stats = {}
            for key, value in stats.items():
                k = key.decode('utf-8') if isinstance(key, bytes) else key
                v = value.decode('utf-8') if isinstance(value, bytes) else value
                decoded_stats[k] = v
            return decoded_stats
        except Exception as e:
            app.logger.error(f"Cache STATS error: {e}")
            return {}

    def flush_all(self):
        """Flush all cache entries."""
        try:
            self.client.flush_all()
            return True
        except Exception as e:
            app.logger.error(f"Cache FLUSH error: {e}")
            return False


cache_manager = CacheManager(cache_client)


def generate_cache_key(*args, **kwargs):
    """Generate a consistent cache key from arguments."""
    key_data = json.dumps({'args': args, 'kwargs': kwargs}, sort_keys=True)
    return hashlib.md5(key_data.encode()).hexdigest()


# --- Decorators ---

def cache_response(ttl=None, key_prefix='api'):
    """Decorator to cache API endpoint responses."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            # Build cache key from request
            cache_key = f"{key_prefix}:{request.path}:{generate_cache_key(
                str(request.args), str(request.form)
            )}"

            # Try to get from cache
            cached = cache_manager.get(cache_key)
            if cached is not None:
                response = jsonify(cached)
                response.headers['X-Cache'] = 'HIT'
                return response

            # Execute function and cache result
            result = f(*args, **kwargs)

            # Handle both tuple returns (response, status_code) and direct returns
            if isinstance(result, tuple):
                response_data, status_code = result[0], result[1] if len(result) > 1 else 200
            else:
                response_data = result
                status_code = 200

            # Only cache successful responses
            if status_code == 200:
                effective_ttl = ttl or app.config['API_CACHE_TTL']
                cache_manager.set(cache_key, response_data, ttl=effective_ttl)
                cache_manager.track_key(key_prefix, cache_key)

            response = jsonify(response_data)
            response.headers['X-Cache'] = 'MISS'
            if isinstance(result, tuple) and len(result) > 1:
                return response, status_code
            return response

        return decorated_function
    return decorator


def cache_db_query(ttl=None, key_prefix='db'):
    """Decorator to cache database query results."""
    def decorator(f):
        @wraps(f)
        def decorated_function(*args, **kwargs):
            cache_key = f"{key_prefix}:{f.__name__}:{generate_cache_key(*args, **kwargs)}"

            # Try cache first
            cached = cache_manager.get(cache_key)
            if cached is not None:
                app.logger.debug(f"DB Cache HIT: {cache_key}")
                return cached

            # Execute query
            result = f(*args, **kwargs)

            # Cache the result
            effective_ttl = ttl or app.config['DB_CACHE_TTL']
            cache_manager.set(cache_key, result, ttl=effective_ttl)
            cache_manager.track_key(key_prefix, cache_key)

            app.logger.debug(f"DB Cache MISS: {cache_key}")
            return result

        return decorated_function
    return decorator


