@app.route('/api/expensive-computation')
@cache_response(ttl=300, key_prefix='api:computation')
def expensive_computation():
    """Simulate an expensive computation that benefits from caching."""
    n = request.args.get('n', 35, type=int)
    n = min(n, 40)  # Safety limit

    start_time = time.time()

    # Simulate expensive computation (iterative fibonacci)
    def fibonacci(num):
        if num <= 1:
            return num
        a, b = 0, 1
        for _ in range(2, num + 1):
            a, b = b, a + b
        return b

    result = fibonacci(n)
    computation_time = time.time() - start_time

    return {
        'input': n,
        'fibonacci_result': result,
        'computation_time_seconds': round(computation_time, 6),
        'note': 'Subsequent requests will be served from cache',
    }


