@app.route('/health')
def health_check():
    """Health check endpoint with cache connectivity test."""
    cache_healthy = False
    try:
        test_key = '_health_check'
        cache_manager.set(test_key, {'status': 'ok', 'timestamp': time.time()}, ttl=10)
        result = cache_manager.get(test_key)
        cache_healthy = result is not None
        cache_manager.delete(test_key)
    except Exception as e:
        app.logger.error(f"Health check cache error: {e}")

    status = 'healthy' if cache_healthy else 'degraded'
    status_code = 200 if cache_healthy else 503

    return jsonify({
        'status': status,
        'components': {
            'application': 'healthy',
            'memcached': 'healthy' if cache_healthy else 'unhealthy',
        },
        'timestamp': time.time(),
    }), status_code


# --- Middleware for Response Timing ---

@app.before_request
def before_request():
    """Record request start time."""
    request._start_time = time.time()


@app.after_request
def after_request(response):
    """Add response timing headers."""
    if hasattr(request, '_start_time'):
        elapsed = time.time() - request._start_time
        response.headers['X-Response-Time'] = f"{elapsed:.6f}s"
    return response


